import subprocess

def get_last_login_records(username: str) -> str:
    """
    Retrieve the most recent login records for a specific user using the `last` command.

    Args:
        username: The username whose login records are to be queried.

    Returns:
        Raw text of the user's most recent login records.
    """
    try:
        # Execute 'last' command to get all login records
        last_result = subprocess.run(
            ['last'],
            capture_output=True,
            text=True,
            check=True
        )

        # Filter records for the specified username
        filtered_records = []
        for line in last_result.stdout.splitlines():
            if username in line:
                filtered_records.append(line)

        return '\n'.join(filtered_records)
    except subprocess.CalledProcessError as e:
        return f"Error executing 'last' command: {e}"
    except Exception as e:
        return f"Unexpected error: {e}"

